<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    validation_loss </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> cross_validation(model, training_data)</span></span>
